  ...
  application_logging: {
    forwarding: {
      labels: {
        exclude: ['label1', 'label2']
      }
    }
  }
  ...
});

// Exclude labels using environment variable
// NEW_RELIC_APPLICATION_LOGGING_FORWARDING_LABELS_EXCLUDE=label1,label2
