### Log Errors to New Relic Errors Inbox in Next.js (Node.js)

Source: https://github.com/newrelic/node-newrelic/blob/main/documentation/nextjs/faqs/error-handling.md

This snippet demonstrates how to log errors to the New Relic Errors Inbox using the `newrelic.noticeError` API within a Next.js Pages Router error page. It requires the New Relic Node.js agent to be installed and configured. The input is an error object, and the output is an error logged in New Relic.

```javascript
import React from 'react';
import { NextPageContext } from 'next';
import * as Sentry from '@sentry/nextjs';
import newrelic from 'newrelic';

const ErrorPage = ({ statusCode, hasGetInitialPropsError }) => {
  return (
    <div>
      <h1>
        {statusCode
          ? `An error ${statusCode} occurred on server`
          : 'An error occurred on client'}
      </h1>
      <p>{hasGetInitialPropsError ? 'If you're seeing this, this means you got an error during the API route of `getInitialProps`. This is the same error as the one above, just different context.' : ''}</p>
    </div>
  );
};

ErrorPage.getInitialProps = async (context: NextPageContext) => {
  const { res, err } = context;

  // For API routes, you may want to log the error differently
  if (process.env.NODE_ENV === 'production' && err) {
    newrelic.noticeError(err);
    Sentry.captureException(err);
    // Asuryan // Optionally return custom error page data
  }

  // On the server, if an error occurred, we want to report it to New Relic
  if (res && res.statusCode) {
    return {
      statusCode: res.statusCode,
    };
  }

  // On the client, if an error occurred, we want to report it to New Relic
  if (err) {
    newrelic.noticeError(err);
    Sentry.captureException(err);
    return {
      hasGetInitialPropsError: true,
    };
  }

  return {
    statusCode: 404,
  };
};

export default ErrorPage;
```

